<script setup lang="ts">
import { computed, ref } from 'vue';
import { useRouter } from 'vue-router';
import { Download, TrendingDown, TrendingUp } from 'lucide-vue-next';
import { exportCsv } from '@/utils/exportCsv';
import { useAdminStore } from '@/store/useAdminStore';
import dayjs from 'dayjs';

interface DayRecord {
  date: string;
  weekday: string;
  isToday?: boolean;
  rate: number;
  normal: number;
  absent: number;
  unsigned: number;
}

type Period = 'today' | 'week' | 'month';

const PERIOD_TABS: { key: Period; label: string }[] = [
  { key: 'today', label: '今日' },
  { key: 'week', label: '本周' },
  { key: 'month', label: '本月' },
];

const PERIOD_LABEL: Record<Period, string> = {
  today: '今日',
  week: '本周',
  month: '本月',
};

const TODAY = computed(() => dayjs().format('YYYY-MM-DD'));

const WEEKDAY_CN: Record<number, string> = {
  0: '星期日',
  1: '星期一',
  2: '星期二',
  3: '星期三',
  4: '星期四',
  5: '星期五',
  6: '星期六',
};

function formatDateCN(dateStr: string): string {
  const d = new Date(dateStr + 'T00:00:00');
  return `${d.getMonth() + 1}月${d.getDate()}日`;
}

function getWeekdayCN(dateStr: string): string {
  const d = new Date(dateStr + 'T00:00:00');
  return WEEKDAY_CN[d.getDay()];
}

function getPeriodDates(period: Period): string[] {
  const base = new Date(TODAY.value + 'T00:00:00');
  let days: number;
  if (period === 'today') days = 1;
  else if (period === 'week') days = 7;
  else days = 30;

  const dates: string[] = [];
  for (let i = 0; i < days; i++) {
    const d = new Date(base);
    d.setDate(d.getDate() - i);
    dates.push(d.toISOString().slice(0, 10));
  }
  return dates;
}

const router = useRouter();
const adminStore = useAdminStore();
const period = ref<Period>('week');
const toast = ref(false);
const toastMsg = ref('');
const exporting = ref(false);
let toastTimer: ReturnType<typeof setTimeout> | null = null;

const periodDates = computed(() => getPeriodDates(period.value));

const overview = computed(() => {
  const periodRecords = adminStore.records.filter((r) => periodDates.value.includes(r.date));
  const normal = periodRecords.filter((r) => r.status === 'signedIn').length;
  const absent = periodRecords.filter((r) => r.status === 'absent').length;
  const unsigned = periodRecords.filter((r) => r.status === 'unsigned').length;
  const total = periodRecords.length;
  const rate = total > 0 ? Math.round((normal / total) * 100) : 0;
  return { rate, normal, absent, unsigned };
});

const days = computed<DayRecord[]>(() => {
  const result: DayRecord[] = [];
  const uniqueDates = [...new Set(periodDates.value)];
  for (const dateStr of uniqueDates) {
    const dayRecords = adminStore.records.filter((r) => r.date === dateStr);
    const normal = dayRecords.filter((r) => r.status === 'signedIn').length;
    const absent = dayRecords.filter((r) => r.status === 'absent').length;
    const unsigned = dayRecords.filter((r) => r.status === 'unsigned').length;
    const total = dayRecords.length;
    const rate = total > 0 ? Math.round((normal / total) * 100) : 0;
    result.push({
      date: formatDateCN(dateStr),
      weekday: getWeekdayCN(dateStr),
      isToday: dateStr === TODAY.value,
      rate,
      normal,
      absent,
      unsigned,
    });
  }
  return result;
});

const attendTop3 = computed(() => {
  const weekDates = getPeriodDates('week');
  const weekRecords = adminStore.records.filter((r) => weekDates.includes(r.date));
  const countMap = new Map<string, number>();
  for (const r of weekRecords) {
    if (r.status === 'signedIn') {
      countMap.set(r.merchantId, (countMap.get(r.merchantId) ?? 0) + 1);
    }
  }
  const sorted = [...countMap.entries()].sort((a, b) => b[1] - a[1]).slice(0, 3);
  return sorted.map(([merchantId, count]) => {
    const m = adminStore.merchants.find((mer) => mer.id === merchantId);
    return { id: merchantId, name: m?.name ?? merchantId, floor: m?.floor ?? '', count };
  });
});

const absentTop3 = computed(() => {
  const weekDates = getPeriodDates('week');
  const weekRecords = adminStore.records.filter((r) => weekDates.includes(r.date));
  const countMap = new Map<string, number>();
  for (const r of weekRecords) {
    if (r.status === 'absent') {
      countMap.set(r.merchantId, (countMap.get(r.merchantId) ?? 0) + 1);
    }
  }
  const sorted = [...countMap.entries()].sort((a, b) => b[1] - a[1]).slice(0, 3);
  return sorted.map(([merchantId, count]) => {
    const m = adminStore.merchants.find((mer) => mer.id === merchantId);
    return { id: merchantId, name: m?.name ?? merchantId, floor: m?.floor ?? '', count };
  });
});

function showToast(msg: string) {
  toastMsg.value = msg;
  toast.value = true;
  if (toastTimer) clearTimeout(toastTimer);
  toastTimer = setTimeout(() => (toast.value = false), 2000);
}

function handleExport() {
  exporting.value = true;
  try {
    const rows = days.value.map((d) => ({
      日期: d.date,
      星期: d.weekday,
      到岗率: `${d.rate}%`,
      正常户数: d.normal,
      缺勤户数: d.absent,
      未签到户数: d.unsigned,
    }));
    exportCsv(rows, `全商场_${PERIOD_LABEL[period.value]}考勤报表`);
    showToast(`已导出全商场${PERIOD_LABEL[period.value]}考勤报表`);
  } finally {
    exporting.value = false;
  }
}
</script>

<template>
  <div class="h-full overflow-y-auto bg-base no-scrollbar">
    <div class="flex flex-col gap-2 px-gutter pb-4 pt-4">
      <!-- 顶部标题区 -->
      <div class="pb-1">
        <h1 class="text-[20px] font-bold text-ink">记录</h1>
        <p class="mt-0.5 text-[12px] text-muted">查看历史签到记录与报表</p>
      </div>

      <!-- 周期切换 Tab -->
      <div class="flex rounded-lg bg-card p-1 shadow-sm">
        <button
          v-for="t in PERIOD_TABS"
          :key="t.key"
          type="button"
          class="flex-1 rounded-md py-1.5 text-[13px] font-medium transition-all"
          :class="period === t.key ? 'bg-primary text-white shadow-sm' : 'text-muted'"
          @click="period = t.key"
        >
          {{ t.label }}
        </button>
      </div>

      <!-- 概览 4 宫格卡 -->
      <div class="rounded-card bg-card px-5 py-4 shadow-[0_4px_12px_-6px_rgba(0,0,0,0.08)]">
        <div class="mb-3 flex items-center justify-between">
          <span class="text-[12px] font-medium text-ink">
            {{ PERIOD_LABEL[period] }}考勤概览
          </span>
          <button
            type="button"
            class="flex items-center gap-1 rounded-full bg-primary px-3 py-1 text-[11px] font-medium text-white active:scale-95"
            :disabled="exporting"
            @click="handleExport"
          >
            <Download :size="11" />
            导出{{ PERIOD_LABEL[period] }}报表
          </button>
        </div>
        <div class="grid grid-cols-4 gap-1.5">
          <div class="flex flex-col items-center justify-center rounded-lg bg-primary-light py-3">
            <span class="text-[18px] font-bold leading-none text-primary">{{ overview.rate }}%</span>
            <span class="mt-1.5 text-[10px] text-primary">到岗率</span>
          </div>
          <div class="flex flex-col items-center justify-center rounded-lg bg-primary-light py-3">
            <span class="text-[18px] font-bold leading-none text-primary">{{ overview.normal }}</span>
            <span class="mt-1.5 text-[10px] text-primary">已到岗</span>
          </div>
          <div class="flex flex-col items-center justify-center rounded-lg bg-warning-light py-3">
            <span class="text-[18px] font-bold leading-none text-warning">{{ overview.absent }}</span>
            <span class="mt-1.5 text-[10px] text-warning">缺勤</span>
          </div>
          <div class="flex flex-col items-center justify-center rounded-lg bg-base py-3">
            <span class="text-[18px] font-bold leading-none text-ink">{{ overview.unsigned }}</span>
            <span class="mt-1.5 text-[10px] text-muted">未签到</span>
          </div>
        </div>
      </div>

      <!-- 榜单左右并排 -->
      <div class="grid grid-cols-2 gap-3">
        <!-- 考勤榜 -->
        <div class="rounded-card bg-card px-3.5 py-3.5 shadow-[0_4px_12px_-6px_rgba(0,0,0,0.08)]">
          <div class="mb-2.5 flex items-center gap-1">
            <TrendingUp :size="13" class="text-primary" />
            <span class="text-[12px] font-semibold text-ink">考勤榜</span>
          </div>
          <div class="space-y-1.5">
            <button
              v-for="(m, idx) in attendTop3"
              :key="m.id"
              type="button"
              class="flex w-full items-center gap-2 rounded-lg bg-base px-2 py-2 active:scale-[0.98]"
              @click="router.push(`/merchant/${m.id}`)"
            >
              <span
                class="flex h-5 w-5 shrink-0 items-center justify-center rounded-full text-[10px] font-bold text-white"
                :class="idx === 0 ? 'bg-primary' : idx === 1 ? 'bg-primary/70' : 'bg-primary/50'"
              >
                {{ idx + 1 }}
              </span>
              <div class="min-w-0 flex-1 text-left">
                <div class="truncate text-[12px] font-medium text-ink">{{ m.name }}</div>
                <div class="text-[10px] text-muted">{{ m.floor }}</div>
              </div>
              <span class="text-[11px] font-bold text-primary">{{ m.count }}天</span>
            </button>
          </div>
        </div>

        <!-- 缺勤榜 -->
        <div class="rounded-card bg-card px-3.5 py-3.5 shadow-[0_4px_12px_-6px_rgba(0,0,0,0.08)]">
          <div class="mb-2.5 flex items-center gap-1">
            <TrendingDown :size="13" class="text-warning" />
            <span class="text-[12px] font-semibold text-ink">缺勤榜</span>
          </div>
          <div class="space-y-1.5">
            <button
              v-for="(m, idx) in absentTop3"
              :key="m.id"
              type="button"
              class="flex w-full items-center gap-2 rounded-lg bg-base px-2 py-2 active:scale-[0.98]"
              @click="router.push(`/merchant/${m.id}`)"
            >
              <span
                class="flex h-5 w-5 shrink-0 items-center justify-center rounded-full text-[10px] font-bold text-white"
                :class="idx === 0 ? 'bg-warning' : idx === 1 ? 'bg-warning/70' : 'bg-warning/50'"
              >
                {{ idx + 1 }}
              </span>
              <div class="min-w-0 flex-1 text-left">
                <div class="truncate text-[12px] font-medium text-ink">{{ m.name }}</div>
                <div class="text-[10px] text-muted">{{ m.floor }}</div>
              </div>
              <span class="text-[11px] font-bold text-warning">{{ m.count }}次</span>
            </button>
          </div>
        </div>
      </div>

      <!-- 按日分组记录列表 -->
      <div class="flex flex-col gap-2.5">
        <div
          v-for="d in days"
          :key="d.date"
          class="rounded-card bg-card px-4 py-3.5 shadow-[0_4px_12px_-6px_rgba(0,0,0,0.08)]"
        >
          <div class="flex items-center justify-between">
            <div class="flex items-center gap-1.5">
              <span class="text-[14px] font-semibold text-ink">{{ d.date }}</span>
              <span class="text-[12px] text-muted">{{ d.weekday }}</span>
              <span v-if="d.isToday" class="rounded bg-primary px-1.5 py-0.5 text-[10px] font-medium text-white">
                今天
              </span>
            </div>
            <span class="text-[13px] font-bold text-primary">{{ d.rate }}%</span>
          </div>
          <div class="mt-3 flex items-center gap-2">
            <div class="flex flex-1 items-center justify-center gap-1 rounded-lg bg-primary-light py-2">
              <span class="text-[16px] font-bold leading-none text-primary">{{ d.normal }}</span>
              <span class="text-[11px] text-primary">正常</span>
            </div>
            <div class="flex flex-1 items-center justify-center gap-1 rounded-lg bg-warning-light py-2">
              <span class="text-[16px] font-bold leading-none text-warning">{{ d.absent }}</span>
              <span class="text-[11px] text-warning">缺勤</span>
            </div>
            <div class="flex flex-1 items-center justify-center gap-1 rounded-lg bg-base py-2">
              <span class="text-[16px] font-bold leading-none text-ink">{{ d.unsigned }}</span>
              <span class="text-[11px] text-muted">未签到</span>
            </div>
          </div>
        </div>
      </div>
    </div>

    <!-- toast -->
    <div
      v-if="toast"
      class="fixed inset-x-0 top-1/2 z-50 flex -translate-y-1/2 justify-center px-gutter"
    >
      <div class="rounded-xl bg-black/85 px-4 py-3 text-center text-[12px] text-white shadow-lg">
        {{ toastMsg }}
      </div>
    </div>
  </div>
</template>
